      if (options.name) {
        elem.name = options.name;
        after.name = options.name;
      }

      if (options.description !== undefined) {
        elem.description = options.description || undefined;
        after.description = options.description || undefined;
      }

      if (parsedProperties) {
        elem.attributes = { ...elem.attributes, ...parsedProperties };
        after.attributes = {
          ...(after.attributes as Record<string, unknown>),
          ...parsedProperties,
        };
      }

