      commandSpan = startSpan(`${commandName}.execute`, {
        "command.name": commandName,
        "command.args": JSON.stringify(commandArgs),
      });
    }
  })
  .hook("postAction", async () => {
    // Automatic telemetry: End command span
    if (isTelemetryEnabled && commandSpan) {
