     1→/**
     2→ * Integration tests for CLI commands
     3→ * These tests verify complete command workflows using temporary directories
     4→ */
     5→
     6→import { describe, it, expect, beforeEach, afterEach } from "bun:test";
     7→import { Model } from "../../src/core/model.js";
     8→import { fileExists } from "../../src/utils/file-io.js";
     9→import { runDr as runDrHelper } from "../helpers/cli-runner.js";
    10→import { createTestWorkdir } from "../helpers/golden-copy.js";
    11→
    12→let tempDir: { path: string; cleanup: () => Promise<void> } = { path: "", cleanup: async () => {} };
    13→
    14→/**
    15→ * Wrapper around the cli-runner helper
    16→ */
    17→async function runDr(
    18→  ...args: string[]
    19→): Promise<{ exitCode: number; stdout: string; stderr: string }> {
    20→  if (!tempDir.path) {
    21→    throw new Error("tempDir.path is not initialized. Parent beforeEach may not have completed.");
    22→  }
    23→  return runDrHelper(args, { cwd: tempDir.path });
    24→}
    25→
    26→/**
    27→ * Ensure parent beforeEach has completed before running nested setup
    28→ */
    29→async function ensureSetup() {
    30→  if (!tempDir.path) {
    31→    throw new Error("Parent setup has not completed. Cannot proceed with test.");
    32→  }
    33→}
    34→
    35→describe("CLI Commands Integration Tests", () => {
    36→  beforeEach(async () => {
    37→    tempDir = await createTestWorkdir();
    38→  });
    39→
    40→  afterEach(async () => {
    41→    await tempDir.cleanup();
    42→  });
    43→
    44→  describe("init command", () => {
    45→    // Note: init tests are skipped because the golden-copy test helper already provides
    46→    // a pre-initialized model. Init command testing is covered in init-specific test files.
    47→    // These tests are replaced with basic model verification to ensure golden copy is properly initialized.
    48→
    49→    it("should have a pre-initialized model from golden copy", async () => {
    50→      // Verify model directory exists and contains manifest
    51→      expect(await fileExists(`${tempDir.path}/documentation-robotics/model/manifest.yaml`)).toBe(
    52→        true
    53→      );
    54→
    55→      // Verify layer directories were created
    56→      for (let i = 1; i <= 12; i++) {
    57→        const layerNum = String(i).padStart(2, "0");
    58→        const layers = [
    59→          "motivation",
    60→          "business",
    61→          "security",
    62→          "application",
    63→          "technology",
    64→          "api",
    65→          "data-model",
    66→          "data-store",
    67→          "ux",
    68→          "navigation",
    69→          "apm",
    70→          "testing",
    71→        ];
    72→        const layerDir = `${tempDir.path}/documentation-robotics/model/${layerNum}_${layers[i - 1]}`;
    73→        expect(await fileExists(layerDir)).toBe(true);
    74→      }
    75→    });
    76→
    77→    it("should fail if trying to init when model already exists", async () => {
    78→      // Try to initialize again (model already exists from golden copy)
    79→      const result = await runDr("init", "--name", "Second Model");
    80→
    81→      expect(result.exitCode).toBe(1);
    82→    });
    83→  });
    84→
    85→  describe("add command", () => {
    86→    // Model is already initialized in the global beforeEach hook
    87→
    88→    it("should add an element to a layer", async () => {
    89→      const result = await runDr("add", "motivation", "goal", "Test Goal");
    90→
    91→      expect(result.exitCode).toBe(0);
    92→
    93→      // Verify element was created
    94→      const model = await Model.load(tempDir.path);
    95→      const layer = await model.getLayer("motivation");
    96→      expect(layer).toBeDefined();
    97→      const element = layer!.getElement("motivation.goal.test-goal");
    98→      expect(element).toBeDefined();
    99→      expect(element!.name).toBe("Test Goal");
   100→    });
   101→
   102→    it("should add element with properties", async () => {
   103→      const result = await runDr(
   104→        "add",
   105→        "motivation",
   106→        "goal",
   107→        "Test Goal",
   108→        "--attributes",
   109→        JSON.stringify({ required: true })
   110→      );
   111→
   112→      expect(result.exitCode).toBe(0);
   113→
   114→      const model = await Model.load(tempDir.path);
   115→      const layer = await model.getLayer("motivation");
   116→      const element = layer!.getElement("motivation.goal.test-goal");
   117→      expect(element!.attributes.required).toBe(true);
   118→    });
   119→
   120→    it("should fail if element already exists", async () => {
   121→      // Add element first
   122→      await runDr("add", "motivation", "goal", "Test Goal");
   123→
   124→      // Try to add again
   125→      const result = await runDr("add", "motivation", "goal", "Test Goal");
   126→
   127→      expect(result.exitCode).toBe(1);
   128→    });
   129→
   130→    it("should fail with invalid JSON properties", async () => {
   131→      const result = await runDr(
   132→        "add",
   133→        "motivation",
   134→        "goal",
   135→        "Test Goal",
   136→        "--attributes",
   137→        "not-json"
   138→      );
   139→
   140→      expect(result.exitCode).toBe(1);
   141→    });
   142→
   143→    it("should support --description option", async () => {
   144→      const result = await runDr(
   145→        "add",
   146→        "api",
   147→        "operation",
   148→        "Test Operation",
   149→        "--description",
   150→        "A test operation"
   151→      );
   152→
   153→      expect(result.exitCode).toBe(0);
   154→
   155→      const model = await Model.load(tempDir.path);
   156→      const layer = await model.getLayer("api");
   157→      const element = layer!.getElement("api.operation.test-operation");
   158→      expect(element!.description).toBe("A test operation");
   159→    });
   160→
   161→    it("should support complex JSON properties", async () => {
   162→      const complexProps = {
   163→        method: "POST",
   164→        path: "/api/users",
   165→        parameters: [{ name: "id", type: "string", required: true }],
   166→        tags: ["user", "api"],
   167→      };
   168→
   169→      const result = await runDr(
   170→        "add",
   171→        "api",
   172→        "operation",
   173→        "Create User",
   174→        "--attributes",
   175→        JSON.stringify(complexProps)
   176→      );
   177→
   178→      expect(result.exitCode).toBe(0);
   179→
   180→      const model = await Model.load(tempDir.path);
   181→      const layer = await model.getLayer("api");
   182→      const element = layer!.getElement("api.operation.create-user");
   183→      expect(element!.attributes.method).toBe("POST");
   184→      expect(element!.attributes.path).toBe("/api/users");
   185→      expect((element!.attributes.parameters as any[]).length).toBe(1);
   186→    });
   187→
   188→    it("should support all options together", async () => {
   189→      const props = { version: "1.0", deprecated: false };
   190→
   191→      const result = await runDr(
   192→        "add",
   193→        "business",
   194→        "businessservice",
   195→        "Test Service",
   196→        "--description",
   197→        "A comprehensive service test",
   198→        "--attributes",
   199→        JSON.stringify(props)
   200→      );
   201→
   202→      expect(result.exitCode).toBe(0);
   203→
   204→      const model = await Model.load(tempDir.path);
   205→      const layer = await model.getLayer("business");
   206→      const element = layer!.getElement("business.businessservice.test-service");
   207→      expect(element!.name).toBe("Test Service");
   208→      expect(element!.description).toBe("A comprehensive service test");
   209→      expect(element!.attributes.version).toBe("1.0");
   210→    });
   211→
   212→    it("should fail when --name is missing", async () => {
   213→      const result = await runDr("add", "motivation", "goal");
   214→
   215→      expect(result.exitCode).toBe(1);
   216→      expect(result.stderr).toContain("required");
   217→    });
   218→
   219→    it("should fail with invalid element ID containing underscores", async () => {
   220→      // With Python format, underscores in names are auto-converted to hyphens
   221→      // so this test now passes and creates motivation.goal.test-goal
   222→      const result = await runDr("add", "motivation", "goal", "test_goal_test");
   223→
   224→      expect(result.exitCode).toBe(0); // Now succeeds - underscores converted to hyphens
   225→    });
   226→
   227→    it("should handle special characters in name and description", async () => {
   228→      const result = await runDr(
   229→        "add",
   230→        "motivation",
   231→        "goal",
   232→        "Test Goal (Priority: Critical)",
   233→        "--description",
   234→        "Description with special chars: @#$%"
   235→      );
   236→
   237→      expect(result.exitCode).toBe(0);
   238→
   239→      const model = await Model.load(tempDir.path);
   240→      const layer = await model.getLayer("motivation");
   241→      // Note: toKebabCase preserves special chars but removes spaces
   242→      const element = layer!.getElement("motivation.goal.test-goal-(priority:-critical)");
   243→      expect(element!.name).toContain("Priority");
   244→      expect(element!.description).toContain("special");
   245→    });
   246→  });
   247→
   248→  describe("update command", () => {
